import{_ as e,c as t,o,a1 as l}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"平台功能: AI 额度查询 | opencode-mystatus","description":"学习 opencode-mystatus 支持的 AI 平台额度查询功能。涵盖 OpenAI、智證 AI、GitHub Copilot 和 Google Cloud 四大平台。","frontmatter":{"title":"平台功能: AI 额度查询 | opencode-mystatus","sidebarTitle":"平台功能","subtitle":"平台功能: AI 额度查询","description":"学习 opencode-mystatus 支持的 AI 平台额度查询功能。涵盖 OpenAI、智證 AI、GitHub Copilot 和 Google Cloud 四大平台。","order":2},"headers":[],"relativePath":"zh-tw/vbgate/opencode-mystatus/platforms/index.md","filePath":"zh-tw/vbgate/opencode-mystatus/platforms/index.md"}'),i={name:"zh-tw/vbgate/opencode-mystatus/platforms/index.md"};function r(d,a,n,s,u,h){return o(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="平台功能" tabindex="-1">平台功能 <a class="header-anchor" href="#平台功能" aria-label="Permalink to &quot;平台功能&quot;">​</a></h1><p>本章節詳細介紹 opencode-mystatus 支援的各個 AI 平台的額度查詢功能。</p><h2 id="支援的平台" tabindex="-1">支援的平台 <a class="header-anchor" href="#支援的平台" aria-label="Permalink to &quot;支援的平台&quot;">​</a></h2><p>opencode-mystatus 支援以下 4 個主流 AI 平台：</p><table tabindex="0"><thead><tr><th>平台</th><th>限額類型</th><th>特點</th></tr></thead><tbody><tr><td>OpenAI</td><td>3 小時 / 24 小時滑動視窗</td><td>支援 Plus、Team、Pro 訂閱</td></tr><tr><td>智證 AI</td><td>5 小時 Token / MCP 月度配額</td><td>支援 Coding Plan</td></tr><tr><td>GitHub Copilot</td><td>月度配額</td><td>顯示 Premium Requests 使用量</td></tr><tr><td>Google Cloud</td><td>按模型獨立計算</td><td>支援多帳號、4 個模型</td></tr></tbody></table><h2 id="平台詳解" tabindex="-1">平台詳解 <a class="header-anchor" href="#平台詳解" aria-label="Permalink to &quot;平台詳解&quot;">​</a></h2><h3 id="openai-額度" tabindex="-1"><a href="./openai-usage/">OpenAI 額度</a> <a class="header-anchor" href="#openai-額度" aria-label="Permalink to &quot;[OpenAI 額度](./openai-usage/)&quot;">​</a></h3><p>深入瞭解 OpenAI 的額度查詢機制：</p><ul><li>3 小時和 24 小時滑動視窗的區別</li><li>Team 帳號的額度共用機制</li><li>JWT Token 解析取得帳號資訊</li></ul><h3 id="智證-ai-額度" tabindex="-1"><a href="./zhipu-usage/">智證 AI 額度</a> <a class="header-anchor" href="#智證-ai-額度" aria-label="Permalink to &quot;[智證 AI 額度](./zhipu-usage/)&quot;">​</a></h3><p>瞭解智證 AI 和 Z.ai 的額度查詢：</p><ul><li>5 小時 Token 限額的計算方式</li><li>MCP 月度配額的用途</li><li>API Key 脫敏顯示</li></ul><h3 id="github-copilot-額度" tabindex="-1"><a href="./copilot-usage/">GitHub Copilot 額度</a> <a class="header-anchor" href="#github-copilot-額度" aria-label="Permalink to &quot;[GitHub Copilot 額度](./copilot-usage/)&quot;">​</a></h3><p>掌握 GitHub Copilot 的額度管理：</p><ul><li>Premium Requests 的含義</li><li>不同訂閱類型的配額差異</li><li>月度重置時間計算</li></ul><h3 id="google-cloud-額度" tabindex="-1"><a href="./google-usage/">Google Cloud 額度</a> <a class="header-anchor" href="#google-cloud-額度" aria-label="Permalink to &quot;[Google Cloud 額度](./google-usage/)&quot;">​</a></h3><p>學習 Google Cloud 多帳號額度查詢：</p><ul><li>4 個模型（G3 Pro、G3 Image、G3 Flash、Claude）的區別</li><li>多帳號管理和切換</li><li>認證檔案讀取機制</li></ul><h2 id="選擇指南" tabindex="-1">選擇指南 <a class="header-anchor" href="#選擇指南" aria-label="Permalink to &quot;選擇指南&quot;">​</a></h2><p>根據你使用的平台，選擇對應的教學：</p><ul><li><strong>只用 OpenAI</strong>：直接看 <a href="./openai-usage/">OpenAI 額度</a></li><li><strong>只用智證 AI</strong>：直接看 <a href="./zhipu-usage/">智證 AI 額度</a></li><li><strong>多平台使用者</strong>：建議按順序閱讀所有平台教學</li><li><strong>Google Cloud 使用者</strong>：需要先安裝 <a href="https://github.com/NoeFabris/opencode-antigravity-auth" target="_blank" rel="noreferrer">opencode-antigravity-auth</a> 外掛</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章節後，可以繼續學習 <a href="./../advanced/">進階功能</a>，瞭解更多設定選項。</p>',23)])])}const g=e(i,[["render",r]]);export{c as __pageData,g as default};
